fn main() {
  emit_explicit_env("MOONSHINE_MOBILE_BRIDGE_URL");
  emit_explicit_env("MOONSHINE_MOBILE_BRIDGE_TOKEN");
  tauri_build::build();
}

fn emit_explicit_env(key: &str) {
  println!("cargo:rerun-if-env-changed={key}");

  if let Some(value) = std::env::var_os(key) {
    println!("cargo:rustc-env={key}={}", value.to_string_lossy());
  }
}
